sql:
SELECT name, length, difficulty
FROM trails
WHERE length > (SELECT AVG(length) FROM trails);

SELECT DISTINCT t.trail_id, t.name
FROM trails t
INNER JOIN trail_reviews tr ON t.trail_id = tr.trail_id;

